command:
// Modern stimulant — clinical bright bloom pulse.
if (!game.modules.get("tokenmagic")?.active) return;
if (!token) return;
const filterId = "fishut-tmfx-modern-stimulant";
if (mode === "remove") { await TokenMagic.deleteFiltersOnToken(token, filterId); return; }
await TokenMagic.addUpdateFiltersOnToken(token, [{
  filterType: "bloom",
  filterId,
  blur: 4,
  bloomScale: 1.4,
  threshold: 0.5,
  animated: { bloomScale: { active: true, loopDuration: 1500, animType: "syncCosOscillation", val1: 1.0, val2: 1.6 } }
}]);
